#include<cstdio>
int a[3000005],f[3000005],S[3000005],n;
int read()
{
	int x=0,f=1;
	char c=getchar();
	while(c<'0' || c>'9')
	{
		if(c=='-')	f=-1;
		c=getchar();
	}
	while(c>='0' && c<='9')	x=(x<<1)+(x<<3)+(c^'0'),c=getchar();
	return x*f;
}
void write(int x)
{
	if(x<0)	putchar('-'),x=-x;
	if(x>9)	write(x/10);
	putchar(x%10+'0');
}
int main(){
	n=read();
	for(int i=1;i<=n;++i)	a[i]=read();
	int top=0;
	for(int i=1;i<=n;++i)
	{
		while(top && !(a[S[top]]>=a[i]))	f[S[top--]]=i;
		S[++top]=i;
	}
	for(int i=1;i<=n;++i)	write(f[i]),putchar(' ');
	return 0;
}
